import { useNavigate } from 'react-router-dom';

export default function GroupCard({ id, name, image, members }) {
    const navigate = useNavigate();

    return (
        <div
            onClick={() => navigate(`/groups/${id}`)}
            className="rounded-xl overflow-hidden shadow-md cursor-pointer transition-transform transform hover:scale-105 bg-white"
        >
            <div className="relative w-full h-40">
                <img
                    src={image}
                    alt={name}
                    className="absolute inset-0 w-full h-full object-cover"
                />
            </div>
            <div className="p-4">
                <h2 className="font-semibold text-lg">{name}</h2>
                <p className="text-sm text-gray-600">{members.length} membres</p>
            </div>
        </div>
    );
}
